import { useEffect, useMemo, useRef, useState } from "react";
import { GetRetType, RetType, SpotterResponseResultSchema } from "../type";
import { useMount } from "./lifecycle";

type LoadingModel = Record<React.Key, boolean>;

export const DEFAULT_LOADING_KEY = 'default_loading_key';

export interface useRequestOptions {
    /**
     * 是否自动请求
     */
    autoRequest?: boolean;
    /**
     * 监听依赖
     * 
     * @default []
     * @example
     * const [userId, setUserId] = useState('1');
     * const { data, refresh } = useRequest(() => getUserSchool(userId));
     * useEffect(() => {
     *   refresh();
     * }, [userId]);
     * 
     */
    refreshDeps?: any[];
    /**
     * 共享缓存key
     */
    cacheKey?: string;
}

const CacheData = new Map<string, any>();

/**
 * 高级请求封装，更方便的读取loading数据及data属性，提供更自由的loading操作
 * @param request 请求方法
 * @returns 
 */
export const useRequest = <T extends (...args: any[]) => Promise<any>>(request: T, options?: useRequestOptions) => {
    const [loadingMap, setLoadingMap] = useState<LoadingModel>({
        [DEFAULT_LOADING_KEY]: false,
    } as LoadingModel);
    type ResponseDataModel = GetRetType<T>;
    const { autoRequest, refreshDeps = [], cacheKey } = options ?? {};
    const [data, setData] = useState<ResponseDataModel>();
    const [error, setError] = useState<Error>();
    const requestArgs = useRef<Parameters<T>>();
    const loaded = useRef(false);

    const updateLoading = (status: boolean, id: React.Key = DEFAULT_LOADING_KEY) => {
        setLoadingMap({
            ...loadingMap,
            [id]: status
        })
    }

    const getLoading = (id: React.Key = DEFAULT_LOADING_KEY) => {
        return loadingMap[id];
    }

    const loading = useMemo(() => loadingMap[DEFAULT_LOADING_KEY] as boolean, [loadingMap]);
    /**
     * 
     * @param args 
     * @param loadId 
     * @deprecated
     * @returns 
     */
    const send = (args: Parameters<T>[0], loadId: React.Key = DEFAULT_LOADING_KEY): Promise<RetType<T>> => {
        return new Promise((resolve, reject) => {
            updateLoading(true, loadId);
            request(args)
                .then((res) => {
                    setData(res?.data);
                    resolve(res);
                })
                .catch((error) => reject(error))
                .finally(() => updateLoading(false, loadId));
        });
    };

    const run = (
        ...args: Parameters<T>
    ): Promise<RetType<T>> => {
        return new Promise<RetType<T>>((resolve, reject) => {
            if (cacheKey && CacheData.has(cacheKey)) {
                const _res = CacheData.get(cacheKey);
                setData(_res?.data);
                resolve(_res?.res);
                return;
            }
            updateLoading(true, DEFAULT_LOADING_KEY);
            requestArgs.current = args;
            request(...args)
                .then((res) => {
                    const _data = res?.data;
                    setData(_data);
                    if (cacheKey) {
                        CacheData.set(cacheKey, {
                            data: _data,
                            res: res,
                        });
                    }
                    resolve(res);
                })
                .catch((error) => {
                    setData(undefined); // 清空数据
                    setError(error);
                    reject(error);
                })
                .finally(() => updateLoading(false, DEFAULT_LOADING_KEY));
        });
    };

    useEffect(() => {
        if (autoRequest) {
            run(...(requestArgs.current ?? [] as any));
        }
    }, []);

    useEffect(() => {
        if (!loaded.current) {
            loaded.current = true;
            return;
        }
        if (refreshDeps.length === 0) return;
        run(...(requestArgs.current ?? [] as any));
    }, refreshDeps);

    const refresh = () => run(...(requestArgs.current ?? [] as any));

    const clear = () => {
        setData(undefined);
    };

    return {
        loading,
        data,
        error,
        setData,
        getLoading,
        clear,
        send,
        run,
        refresh,
    };
};

/**
 * 简化详情请求逻辑的hooks, 提供更便捷的loading及data操作
 * @param request 传递接口
 * @param payload 传递接口的参数对象
 * @returns 
 */
export const useDetail = <T extends (...args: any[]) => Promise<SpotterResponseResultSchema>>(
    request: T,
    ...payload: Parameters<T>
) => {
    const [loading, setLoading] = useState(false);
    const [detail, setDetail] = useState<GetRetType<typeof request>>();

    const fetchDetail = async (...args: any[]) => {
        const res = await request(...args);
        setDetail(res.data);
        return res;
    };

    const loadData = () => {
        setLoading(true);
        fetchDetail(...payload).finally(() => {
            setLoading(false);
        });
    }

    useMount(() => {
        loadData();
    });

    /**
     * 重置数据
     */
    const reload = () => {
        loadData();
    }

    return {
        loading,
        setLoading,
        detail,
        reload,
    };
};